var e=[{id:`L2_1`,type:`dialog`,speaker:`PILOT_VOICE_NULL_NULL`,text:{KOREA:`눈보라가 심해서 더이상 계기 비행으로도 접근이 어렵네요. 착륙하겠습니다.`,JPN:`吹雪が酷くてこれ以上は計器飛行でも近づけないです。着陸します。`,ENG:`The blizzard is getting more severe, and we can't get any closer by flight. Proceeding to land.`,TWN:`暴風雪太大，我們無法繼續透過儀錶飛行靠近，只能著陸了。`},stage:{bg:`HELI_NIGHT_3`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`USER_ADMIN_NULL_NULL`,text:{KOREA:`그렇게 해주게.`,JPN:`そうしたまえ。`,ENG:`Understood.`,TWN:`好吧。`},stage:{bg:`HELI_NIGHT_3`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:`PILOT_VOICE_NULL_NULL`,text:{KOREA:`음…?`,JPN:`ん……？`,ENG:`Mm...?`,TWN:`嗯……？`},stage:{bg:`HELI_NIGHT_3`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`PILOT_VOICE_NULL_NULL`,text:{KOREA:`이런!`,JPN:`そんな！`,ENG:`Damn!`,TWN:`糟糕！`},stage:{bg:`HELI_NIGHT_3`,slots:{L:null,C:null,R:null}}},{id:`L11_1`,type:`dialog`,speaker:`PILOT_VOICE_NULL_NULL`,text:{KOREA:`전방에 미확인 기체! 충돌합니다!`,JPN:`前方に未確認機体！　衝突します！`,ENG:`Unidentified aircraft in front! Brace for impact!`,TWN:`前方有不明機體！要撞上了！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:`INTERN_FENRIR_NULL_NULL`,text:{KOREA:`으음…? 네엥? 머라구여??`,JPN:`ううん……？　ふぁい？　なんですかぁ？？`,ENG:`Mm...? Huh? What did you say??`,TWN:`嗯……？什麼什麼？`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`INTERN_FENRIR_NULL_NULL`,text:{KOREA:`흐갸아앗…?!`,JPN:`ふぎゃああ……！？`,ENG:`Eeeep...?!`,TWN:`呀啊啊……？！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_NULL`,text:{KOREA:`무슨 일이죠?!`,JPN:`どうしたんですか！？`,ENG:`What's going on?!`,TWN:`什麼事？！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`LAIKA_CANARY_NULL_NULL`,text:{KOREA:`창 밖을 봐. 눈보라 사이에 시커먼 것들이 날아다니고 있어.`,JPN:`窓の外を見ろ。吹雪の中を真っ黒いやつらが飛んでいる。`,ENG:`Look out the window. There are pitch-black things flying within the blizzard.`,TWN:`看窗外，有一些漆黑的東西在風雪中飛過。`},stage:{bg:`CORRIDOR`,slots:{L:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L20_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_NULL`,text:{KOREA:`저건 비행형 침식체잖아요?`,JPN:`あれは飛行型の侵食体じゃないですか！`,ENG:`Aren't those flying C.O.s?`,TWN:`那是飛行侵蝕體？`},stage:{bg:`CORRIDOR`,slots:{L:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L22_1`,type:`dialog`,speaker:`INTERN_FENRIR_NULL_NULL`,text:{KOREA:`히익, 엄청 많네요. 어느새 이렇게 둘러싸인 거지?`,JPN:`ひいっ、多すぎますね。いつの間に囲まれたの？`,ENG:`Eek...! There are so many of them. When did they surround us?`,TWN:`啊，太多了。什麼時候冒出了這麼多？`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`LAIKA_CANARY_NULL_NULL`,text:{KOREA:`돌진해온다! 뭐라도 붙잡아!`,JPN:`突進してくる！　何かに掴まれ！`,ENG:`They're charging toward us! Grab onto something!`,TWN:`來了！快抓穩！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`PILOT_VOICE_NULL_NULL`,text:{KOREA:`뭐지? 계기판 고장인가?`,JPN:`何だ？　計器板が故障したのか？`,ENG:`Huh? Is the dashboard broken?`,TWN:`怎麼回事？儀錶板故障？`},stage:{bg:`HELI_NIGHT_3`,slots:{L:null,C:null,R:null}}},{id:`L28_1`,type:`dialog`,speaker:`PILOT_VOICE_NULL_NULL`,text:{KOREA:`분명 부딪혔는데, 기체에 손상이 없다고?`,JPN:`確かにぶつかったのに、機体に損傷がない？`,ENG:`Something hit us, but the aircraft took no damage?`,TWN:`明明被擊中了，飛機卻沒有損壞？`},stage:{bg:`HELI_NIGHT_3`,slots:{L:null,C:null,R:null}}}];export{e as default};